        public Graph(int size) {
            idToCity = new HashMap<>();
            cityToId = new HashMap<>();
            adjacencyMatrix = new int[size][size];
            nodeCount = 0;

            // Initialize adjacency matrix with zeros
            for (int i = 0; i < size; i++) {
                for (int j = 0; j < size; j++) {
                    adjacencyMatrix[i][j] = 0;
                }
            }
        }

