                idToCity.put(id, cityName);
                cityToId.put(cityName, id);
                nodeCount++;
            }
        }

        public void addEdge(int sourceId, int destId, int weight) {
            if (sourceId >= 0 && sourceId <= 49 && destId >= 0 && destId <= 49) {
                // Ensure weight is within [10, 100]
                int validWeight = Math.max(10, Math.min(100, weight));
                adjacencyMatrix[sourceId][destId] = validWeight;
            }
        }

        public int getNodeCount() {
            return nodeCount;
        }

        public int[][] getAdjacencyMatrix() {
            return adjacencyMatrix;
        }

