    public static Graph buildGraphFromJsonFile(String filePath) {
        Graph graph = new Graph(50); // Creating a graph with 50 nodes (0-49)

        try {
            JSONParser parser = new JSONParser();
            JSONArray cityArray = (JSONArray) parser.parse(new FileReader(filePath));

            // First pass: create nodes with IDs in range [0, 49]
            for (int i = 0; i < cityArray.size() && i < 50; i++) {
                JSONObject cityObj = (JSONObject) cityArray.get(i);
                String cityName = (String) cityObj.get("cityName");
                graph.addNode(i, cityName);
            }

            // Second pass: add edges with weights in range [10, 100]
            for (int i = 0; i < cityArray.size() && i < 50; i++) {
                JSONObject cityObj = (JSONObject) cityArray.get(i);
                JSONArray distances = (JSONArray) cityObj.get("distances");

                for (int j = 0; j < distances.size() && j < 50; j++) {
                    if (i != j) { // Avoid self-loops
                        long distance = (Long) distances.get(j);
                        int weight = scaleWeight(distance);
                        graph.addEdge(i, j, weight);
                    }
                }
            }

            return graph;

        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

    private static int scaleWeight(long originalDistance) {
        // Scale the original distance to be within [10, 100]
        if (originalDistance <= 0) {
            return 10; // Minimum weight for non-positive distances
        }

        // Linear scaling: map the original distance to [10, 100]
        int scaledWeight = 10 + (int)(originalDistance % 91);
        return Math.max(10, Math.min(100, scaledWeight));
    }
}

