public class EmployeeSalaryGraph {

    public static class Graph {
        private Map<Integer, List<Edge>> adjacencyList;
        private int edgeCount;

        public Graph() {
            adjacencyList = new HashMap<>();
            edgeCount = 0;
        }

        public void addNode(int id) {
            if (id >= 100 && id <= 999 && !adjacencyList.containsKey(id)) {
                adjacencyList.put(id, new ArrayList<>());
            }
        }

        public boolean addEdge(int source, int target, int salaryDiff) {
            if (edgeCount >= 50) {
                return false;
            }

            if (adjacencyList.containsKey(source) && adjacencyList.containsKey(target)) {
                adjacencyList.get(source).add(new Edge(target, salaryDiff));
                edgeCount++;
                return true;
            }

            return false;
        }

        public Map<Integer, List<Edge>> getGraph() {
            return adjacencyList;
        }

        public int getEdgeCount() {
            return edgeCount;
        }
    }

    public static class Edge {
        private int targetId;
        private int salaryDifference;

        public Edge(int targetId, int salaryDifference) {
            this.targetId = targetId;
            this.salaryDifference = salaryDifference;
        }

        public int getTargetId() {
            return targetId;
        }

        public int getSalaryDifference() {
            return salaryDifference;
        }
    }

    public static Graph buildEmployeeSalaryGraph(String jsonFilePath) {
        Graph graph = new Graph();

        try {
            JSONParser parser = new JSONParser();
            JSONArray employeeArray = (JSONArray) parser.parse(new FileReader(jsonFilePath));

            List<Employee> employees = new ArrayList<>();

            // Parse JSON data
            for (Object obj : employeeArray) {
                JSONObject empObj = (JSONObject) obj;
                int id = ((Long) empObj.get("id")).intValue();
                int salary = ((Long) empObj.get("salary")).intValue();
                employees.add(new Employee(id, salary));
            }

            // Assign node IDs within [100, 999] range
            Map<Integer, Integer> empToNodeMap = new HashMap<>();
            int nodeId = 100;

            for (Employee emp : employees) {
                if (nodeId <= 999) {
                    empToNodeMap.put(emp.id, nodeId);
                    graph.addNode(nodeId);
                    nodeId++;
                } else {
                    break; // Stop if we exceed the node ID range
                }
            }

            // Create edges for salary differences less than 5000
            for (int i = 0; i < employees.size() && graph.getEdgeCount() < 50; i++) {
                Employee emp1 = employees.get(i);
                Integer node1 = empToNodeMap.get(emp1.id);

                if (node1 == null) continue;

                for (int j = i+1; j < employees.size() && graph.getEdgeCount() < 50; j++) {
                    Employee emp2 = employees.get(j);
                    Integer node2 = empToNodeMap.get(emp2.id);

                    if (node2 == null) continue;

                    int salaryDiff = Math.abs(emp1.salary - emp2.salary);
                    if (salaryDiff < 5000) {
                        graph.addEdge(node1, node2, salaryDiff);
                    }
                }
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return graph;
    }

    private static class Employee {
        private int id;
        private int salary;

        public Employee(int id, int salary) {
            this.id = id;
            this.salary = salary;
        }
    }
}

